package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertDoesNotThrow;
import static org.junit.jupiter.api.Assertions.assertThrows;

import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatValidateTest {

    private Method validateMethod;

    @BeforeEach
    public void setUp() throws Exception {
        validateMethod = CSVFormat.class.getDeclaredMethod("validate");
        validateMethod.setAccessible(true);
    }

    private void invokeValidate(CSVFormat format) throws Exception {
        validateMethod.invoke(format);
    }

    @Test
    void testValidateDelimiterIsLineBreak() throws Exception {
        CSVFormat format = CSVFormat.newFormat('\n');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("delimiter cannot be a line break"));
    }

    @Test
    void testValidateQuoteCharSameAsDelimiter() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withDelimiter(',').withQuote(',');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("quoteChar character and the delimiter cannot be the same"));
    }

    @Test
    void testValidateEscapeCharSameAsDelimiter() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withDelimiter(';').withEscape(';');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("escape character and the delimiter cannot be the same"));
    }

    @Test
    void testValidateCommentMarkerSameAsDelimiter() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withDelimiter('#').withCommentMarker('#');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("comment start character and the delimiter cannot be the same"));
    }

    @Test
    void testValidateQuoteCharSameAsCommentMarker() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withQuote('#').withCommentMarker('#');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("comment start character and the quoteChar cannot be the same"));
    }

    @Test
    void testValidateEscapeCharSameAsCommentMarker() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withEscape('#').withCommentMarker('#');
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("comment start and the escape character cannot be the same"));
    }

    @Test
    void testValidateNoEscapeCharWhenQuoteModeNone() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withEscape((Character) null).withQuoteMode(QuoteMode.NONE);
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("No quotes mode set but no escape character is set"));
    }

    @Test
    void testValidateHeaderWithDuplicates() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withHeader("a", "b", "a");
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("header contains a duplicate entry"));
    }

    @Test
    void testValidateValidFormatNoException() {
        CSVFormat format = CSVFormat.DEFAULT.withDelimiter(';').withQuote('"').withEscape('\\')
                .withCommentMarker('#').withHeader("a", "b", "c");
        assertDoesNotThrow(() -> {
            try {
                invokeValidate(format);
            } catch (Exception e) {
                throw e.getCause();
            }
        });
    }

    @Test
    void testValidateNullHeader() {
        CSVFormat format = CSVFormat.DEFAULT.withHeader((String[]) null);
        assertDoesNotThrow(() -> {
            try {
                invokeValidate(format);
            } catch (Exception e) {
                throw e.getCause();
            }
        });
    }
}
